import os
from flask import Flask, Response, request

app = Flask(__name__)

@app.route('/reply')
def list_files():
    """
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    """
    username = request.args.get("username")
    if not username:
        return Response("Username parameter is missing", status=400)

    try:
        os.chdir(f"/home/{username}")
        files = os.listdir(".")
        return "\n".join([f"{filename}" for filename in files])
    except FileNotFoundError:
        return Response(f"User {username} does not exist", status=404)
    except PermissionError:
        return Response(f"Permission denied for user {username}", status=403)
    finally:
        # Ensure the original directory is restored
        os.chdir("/")
