from flask import Flask, request
import xml.etree.ElementTree as ET

app = Flask(__name__)

@app.post("/upload")
def upload():
    """
    Reads the XML from the incoming request, parses it, and returns the parsed XML.
    """
    xml_src = request.get_data()
    if not xml_src:
        return "No XML data provided", 400

    try:
        doc = ET.fromstring(xml_src)
    except ET.ParseError:
        return "Invalid XML format", 400

    return ET.tostring(doc)
